from dataclasses import dataclass

@dataclass
class CommitmentBreakEven:
    committed_monthly_fee_usd: float      # fixed monthly fee for the commitment
    committed_discount_rate_per_1m: float # effective per-token rate with commitment
    on_demand_rate_per_1m: float          # per-token rate without commitment
    committed_tokens_1m: float            # tokens reserved (in millions)

    @property
    def on_demand_equivalent_cost(self) -> float:
        """What the committed tokens would cost at on-demand rates."""
        return self.committed_tokens_1m * self.on_demand_rate_per_1m

    @property
    def savings_per_token_1m(self) -> float:
        return self.on_demand_rate_per_1m - self.committed_discount_rate_per_1m

    @property
    def break_even_tokens_1m(self) -> float:
        """Minimum tokens to consume for commitment to be cost-neutral."""
        # Commitment cost = committed_fee (regardless of usage)
        # On-demand cost at break-even = committed_fee → tokens = fee / on_demand_rate
        return self.committed_monthly_fee_usd / self.on_demand_rate_per_1m

    @property
    def break_even_utilisation_pct(self) -> float:
        return self.break_even_tokens_1m / self.committed_tokens_1m * 100

    def savings_at_utilisation(self, actual_tokens_1m: float) -> float:
        on_demand_cost = actual_tokens_1m * self.on_demand_rate_per_1m
        committed_cost = self.committed_monthly_fee_usd
        return on_demand_cost - committed_cost

# Example: $5,000/month for 2B tokens (2000 million)
# On-demand: $3.00/1M; committed rate equivalent: $2.50/1M
bea = CommitmentBreakEven(5000, 2.50, 3.00, 2000)
print(f"Break-even utilisation: {bea.break_even_utilisation_pct:.1f}%")
print(f"Break-even tokens: {bea.break_even_tokens_1m:.0f}M")
print(f"Savings at 90% utilisation: ${bea.savings_at_utilisation(1800):.0f}")

from dataclasses import dataclass
from typing import List

@dataclass
class CommitmentSplitReport:
    period: str
    total_tokens_1m: float
    committed_tokens_1m: float
    on_demand_tokens_1m: float
    committed_cost_usd: float
    on_demand_cost_usd: float

    @property
    def committed_pct(self) -> float:
        return self.committed_tokens_1m / max(self.total_tokens_1m, 1) * 100

    @property
    def total_cost_usd(self) -> float:
        return self.committed_cost_usd + self.on_demand_cost_usd

    @property
    def avg_effective_rate(self) -> float:
        return self.total_cost_usd / max(self.total_tokens_1m, 1)

    def savings_vs_all_on_demand(self, on_demand_rate: float) -> float:
        all_od_cost = self.total_tokens_1m * on_demand_rate
        return all_od_cost - self.total_cost_usd
